import{_ as a,o as r,c as e,a2 as o}from"./chunks/framework.Cd7uensT.js";const b=JSON.parse('{"title":"仪表盘","description":"","frontmatter":{},"headers":[],"relativePath":"guide/features/dashboard.md","filePath":"guide/features/dashboard.md","lastUpdated":1781600659000}'),l={name:"guide/features/dashboard.md"};function d(i,t,n,s,h,g){return r(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="仪表盘" tabindex="-1">仪表盘 <a class="header-anchor" href="#仪表盘" aria-label="Permalink to &quot;仪表盘&quot;">​</a></h1><p>仪表盘是系统的首页，提供数据中心整体运行状态的可视化展示。</p><h2 id="统计卡片" tabindex="-1">统计卡片 <a class="header-anchor" href="#统计卡片" aria-label="Permalink to &quot;统计卡片&quot;">​</a></h2><table tabindex="0"><thead><tr><th>区域</th><th>内容</th></tr></thead><tbody><tr><td><strong>统计卡片</strong></td><td>机房数量、机柜数量、设备总数、运行中设备、维护中设备、已报废设备</td></tr><tr><td><strong>设备状态分布</strong></td><td>各状态设备占比图表</td></tr><tr><td><strong>机柜容量概览</strong></td><td>各机房机柜使用率</td></tr><tr><td><strong>待处理工单</strong></td><td>未完成工单列表</td></tr><tr><td><strong>库存预警</strong></td><td>低库存耗材提醒</td></tr></tbody></table><h2 id="功率监控" tabindex="-1">功率监控 <a class="header-anchor" href="#功率监控" aria-label="Permalink to &quot;功率监控&quot;">​</a></h2><p>功率监控模块展示数据中心的电力负载情况，帮助运维人员掌握能耗分布，预防过载风险。</p><h3 id="监控指标" tabindex="-1">监控指标 <a class="header-anchor" href="#监控指标" aria-label="Permalink to &quot;监控指标&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指标</th><th>说明</th></tr></thead><tbody><tr><td><strong>总功率</strong></td><td>当前数据中心所有设备的总功率消耗（kW）</td></tr><tr><td><strong>机柜功率</strong></td><td>各机柜的实时功率消耗及功率密度分布</td></tr><tr><td><strong>功率使用效率（PUE）</strong></td><td>数据中心总能耗与 IT 设备能耗的比值</td></tr><tr><td><strong>功率阈值告警</strong></td><td>当机柜功率超过设定阈值时触发告警提示</td></tr></tbody></table><h3 id="展示方式" tabindex="-1">展示方式 <a class="header-anchor" href="#展示方式" aria-label="Permalink to &quot;展示方式&quot;">​</a></h3><ul><li><strong>机柜功率热力图</strong>：以热力图方式展示各机柜的功率负载，颜色从绿到红渐变，直观反映功率分布</li><li><strong>功率排行</strong>：按功率消耗排序的设备/机柜 TOP 列表，便于定位高能耗单元</li><li><strong>功率趋势</strong>：展示选定时间范围内的功率变化曲线</li></ul><h2 id="趋势图表" tabindex="-1">趋势图表 <a class="header-anchor" href="#趋势图表" aria-label="Permalink to &quot;趋势图表&quot;">​</a></h2><p>趋势图表模块提供关键指标的历史变化趋势分析，支持不同时间粒度的数据查看。</p><h3 id="趋势类型" tabindex="-1">趋势类型 <a class="header-anchor" href="#趋势类型" aria-label="Permalink to &quot;趋势类型&quot;">​</a></h3><table tabindex="0"><thead><tr><th>趋势类型</th><th>展示内容</th></tr></thead><tbody><tr><td><strong>设备数量趋势</strong></td><td>按日/周/月展示设备总数及各状态设备数量变化曲线</td></tr><tr><td><strong>功率趋势</strong></td><td>按时间维度展示总功率、机柜功率的变化曲线</td></tr><tr><td><strong>工单趋势</strong></td><td>按日/周/月展示工单创建量、完成量的变化趋势</td></tr><tr><td><strong>耗材领用趋势</strong></td><td>展示耗材出入库数量的时间序列变化</td></tr></tbody></table><h3 id="操作方式" tabindex="-1">操作方式 <a class="header-anchor" href="#操作方式" aria-label="Permalink to &quot;操作方式&quot;">​</a></h3><ul><li><strong>时间粒度切换</strong>：支持按日、按周、按月、按年切换统计粒度</li><li><strong>时间范围选择</strong>：支持自定义起止时间，以及近 7 天、近 30 天、近 90 天等快捷选项</li><li><strong>图例交互</strong>：点击图例可显示/隐藏对应数据系列</li><li><strong>数据悬浮</strong>：鼠标悬停在图表数据点上，显示具体数值和日期</li></ul><h2 id="机柜容量分布图" tabindex="-1">机柜容量分布图 <a class="header-anchor" href="#机柜容量分布图" aria-label="Permalink to &quot;机柜容量分布图&quot;">​</a></h2><p>机柜容量分布图以可视化方式展示各机柜的空间使用情况，辅助运维人员快速定位可用资源。</p><h3 id="展示内容" tabindex="-1">展示内容 <a class="header-anchor" href="#展示内容" aria-label="Permalink to &quot;展示内容&quot;">​</a></h3><ul><li><strong>机柜使用率</strong>：以进度条或百分比形式展示每个机柜的 U 位使用率</li><li><strong>分布概览</strong>：按机房维度聚合展示机柜使用率分布状况</li><li><strong>颜色标识</strong>： <ul><li>🟢 绿色：使用率低于 60%，资源充足</li><li>🟡 黄色：使用率 60%～85%，资源适中</li><li>🔴 红色：使用率高于 85%，资源紧张</li></ul></li><li><strong>空闲 U 位统计</strong>：各机房剩余可用 U 位的汇总数据</li></ul><h3 id="交互操作" tabindex="-1">交互操作 <a class="header-anchor" href="#交互操作" aria-label="Permalink to &quot;交互操作&quot;">​</a></h3><ul><li>点击机柜可跳转至该机柜的设备列表详情页</li><li>支持按机房切换查看不同区域的机柜容量</li><li>支持按使用率排序，优先展示资源紧张或资源充足的机柜</li></ul><h2 id="数据刷新机制" tabindex="-1">数据刷新机制 <a class="header-anchor" href="#数据刷新机制" aria-label="Permalink to &quot;数据刷新机制&quot;">​</a></h2><p>仪表盘数据支持多种刷新方式，确保展示内容的实时性和准确性。</p><h3 id="手动刷新" tabindex="-1">手动刷新 <a class="header-anchor" href="#手动刷新" aria-label="Permalink to &quot;手动刷新&quot;">​</a></h3><p>点击仪表盘右上角的「刷新」按钮，立即触发全量数据重新加载。</p><h3 id="自动刷新" tabindex="-1">自动刷新 <a class="header-anchor" href="#自动刷新" aria-label="Permalink to &quot;自动刷新&quot;">​</a></h3><ul><li><strong>默认间隔</strong>：系统每 30 秒自动轮询更新数据</li><li><strong>刷新范围</strong>：自动刷新仅更新统计卡片数值等轻量数据，趋势图表和分布图在切换时间粒度时按需加载</li><li><strong>后台静默</strong>：自动刷新在后台进行，不影响用户当前操作</li></ul><h3 id="刷新状态提示" tabindex="-1">刷新状态提示 <a class="header-anchor" href="#刷新状态提示" aria-label="Permalink to &quot;刷新状态提示&quot;">​</a></h3><ul><li>数据加载中时，相关卡片区域显示加载动画</li><li>数据更新成功后，卡片区域有轻量闪烁提示</li><li>数据加载失败时显示错误提示，并保留上次成功加载的数据</li></ul><h2 id="操作说明" tabindex="-1">操作说明 <a class="header-anchor" href="#操作说明" aria-label="Permalink to &quot;操作说明&quot;">​</a></h2><ul><li><strong>快速跳转</strong>：点击统计卡片可跳转到对应管理页面</li></ul>',32)])])}const c=a(l,[["render",d]]);export{b as __pageData,c as default};
